// src/app/HomeClient.tsx
"use client";

import { useMemo, useState } from "react";
import { FileText, Image } from "lucide-react";

import { DownloadButton } from "@/components/download-button";
import { ErrorAlert } from "@/components/error-alert";
import { JobStatusPanel } from "@/components/job-status-panel";
import { UploadCard } from "@/components/upload-card";
import { useDocumentJob } from "@/hooks/use-document-job";

export function Main() {
  const [contextFiles, setContextFiles] = useState<File[]>([]);
  const [templateFile, setTemplateFile] = useState<File | null>(null);

  const { jobId, updates, error, status, isStreaming, isCompleted, start } =
    useDocumentJob();

  const canStart = useMemo(
    () => Boolean(templateFile) && !isStreaming && !isCompleted,
    [isCompleted, isStreaming, templateFile],
  );

  const downloadPath = useMemo(() => {
    if (!jobId || !templateFile) return "";
    return `/api/download/${jobId}/${encodeURIComponent(templateFile.name)}`;
  }, [jobId, templateFile]);

  return (
    <>
      <div className="grid md:grid-cols-2 gap-6 mb-8">
        <UploadCard
          title="Context Files"
          icon={<Image className="w-5 h-5 text-slate-600" />}
          hint="Optional"
          files={contextFiles}
          onDrop={setContextFiles}
          maxFiles={100}
        />
        <UploadCard
          title="Template File"
          icon={<FileText className="w-5 h-5 text-slate-600" />}
          hint="Required"
          required
          files={templateFile ? [templateFile] : []}
          onDrop={(files) => setTemplateFile(files[0] || null)}
          maxFiles={1}
        />
      </div>

      {error && <ErrorAlert message={error} />}

      <JobStatusPanel
        canStart={canStart}
        isStreaming={isStreaming}
        isCompleted={isCompleted}
        onStart={() => start({ templateFile, contextFiles })}
        updates={updates}
      />

      {isCompleted && downloadPath && (
        <DownloadButton downloadPath={downloadPath} />
      )}
    </>
  );
}